from typing import List


class Solution:
    def graphColoring(self, V: int, edges: List[List[int]], m: int) -> bool:
        # Build adjacency matrix for O(1) edge checks
        adj = [[False] * V for _ in range(V)]
        for u, w in edges:
            adj[u][w] = True
            adj[w][u] = True

        colors = [0] * V  # 0 means uncolored

        def is_safe(vertex: int, color: int) -> bool:
            for neighbor in range(V):
                if adj[vertex][neighbor] and colors[neighbor] == color:
                    return False
            return True

        def solve(vertex: int) -> bool:
            if vertex == V:
                return True
            for color in range(1, m + 1):
                if is_safe(vertex, color):
                    colors[vertex] = color
                    if solve(vertex + 1):
                        return True
                    colors[vertex] = 0  # undo
            return False

        return solve(0)


# ---- brute force oracle ----
class Brute:
    def graphColoring(self, V, edges, m):
        from itertools import product
        eset = [(u, w) for u, w in edges]
        for assign in product(range(1, m + 1), repeat=V):
            if all(assign[u] != assign[w] for u, w in eset):
                return True
        return False


def run_tests():
    s = Solution()
    b = Brute()
    # given examples
    triangle = [[0, 1], [1, 2], [0, 2]]
    assert s.graphColoring(3, triangle, 2) is False
    assert s.graphColoring(3, triangle, 3) is True
    square = [[0, 1], [1, 2], [2, 3], [3, 0]]
    assert s.graphColoring(4, square, 2) is True
    # edge cases
    assert s.graphColoring(1, [], 1) is True          # single vertex
    assert s.graphColoring(1, [], 0) is False         # no colors
    assert s.graphColoring(5, [], 1) is True          # no edges, 1 color
    assert s.graphColoring(2, [[0, 1]], 1) is False   # edge, 1 color
    # disconnected
    assert s.graphColoring(4, [[0, 1], [2, 3]], 2) is True

    # randomized vs brute oracle
    import random
    for _ in range(2000):
        V = random.randint(1, 6)
        m = random.randint(1, 4)
        edges = []
        for u in range(V):
            for w in range(u + 1, V):
                if random.random() < 0.5:
                    edges.append([u, w])
        assert s.graphColoring(V, edges, m) == b.graphColoring(V, edges, m), (V, edges, m)
    print("ALL PASS")


run_tests()
